function solve(matrix) {
    const n = matrix.length;
    const ans = [];

    for (let i = 0; i < n; i++) {
        let degree = 0;
        // Calculate the sum of the i-th row
        for (let j = 0; j < n; j++) {
            // Since matrix[i][i] is guaranteed to be 0, we just sum up all entries
